const buildAllPayrollRows=(agentData,effVol,agentDir)=>{
  const icNum=ic=>{const m=(ic||"").match(/(\d+)$/);return m?parseInt(m[1]):99999;};
  return agentData
    .filter(a=>a.policies.length>0||effVol.some(v=>v.agentUid===a.uid))
    .map(a=>{
      const volDebt=effVol.filter(v=>v.agentUid===a.uid).reduce((s,v)=>s+(v.amount-v.agentComm),0);
      const net=a.totalAgent-volDebt;
      const ic=(agentDir[a.uid]&&agentDir[a.uid].internalCode)||"";
      const name=agentDir[a.uid]?(agentDir[a.uid].name+" "+agentDir[a.uid].surname).trim():a.uid;
      return{uid:a.uid,name,ic,polCount:a.policies.length,accrued:a.totalAgent,volDebt:Math.round(volDebt),net:Math.round(net)};
    })
    .sort((a,b)=>icNum(a.ic)-icNum(b.ic));
};

