  const totMgr=opR.reduce((s,r)=>s+r.mi,0);const totOp=opR.reduce((s,r)=>s+r.oi,0);const totFix=opR.reduce((s,r)=>s+r.fix,0);const totProfit=opR.reduce((s,r)=>s+r.profit,0);
